import { html, customElement, when, state, css, unsafeHTML } from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { FormDesign, FormWorkflowWithTypeSettings } from "@umbraco-forms/generated";
import type {
  UmbTreeElement,
  UmbTreeItemModelBase,
} from "@umbraco-cms/backoffice/tree";
import { FormsFormDetailRepository } from "../../../repository/index.js";
import { FORMS_FORM_TREE_ALIAS } from "../../../tree/manifests.js";
import type { FormsFormCopyWorkflowsOptionsModalData } from "./index.js";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";

@customElement("forms-form-copy-workflows-options-modal")
export class FormsFormCopyWorkflowsOptionsModalElement extends UmbModalBaseElement<FormsFormCopyWorkflowsOptionsModalData> {
  #sourceForm?: FormDesign | null;

  @state()
  private _selectedWorkflows: Array<string> = [];

  @state()
  private _destinationForm?: FormDesign | null;

  #formDetailRepository = new FormsFormDetailRepository(this);

  #notificationContext?: typeof UMB_NOTIFICATION_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(UMB_NOTIFICATION_CONTEXT, (instance) => {
      this.#notificationContext = instance;
    });
  }

  async connectedCallback() {
    super.connectedCallback();

    if (!this.data?.unique) return;
    const { data } = await this.#formDetailRepository.requestByUnique(
      this.data.unique
    );
    if (!data) {
      return;
    }
    this.#sourceForm = data;
    this._selectedWorkflows = this.#allWorkflows(data).map(w => w.id);
    this.requestUpdate();
  }

  #allWorkflows(form: FormDesign) {
    return form.formWorkflows.onSubmit
      .concat(form.formWorkflows.onApprove)
      .concat(form.formWorkflows.onReject);
  }

  #formHasWorkflows(form: FormDesign) {
    return this.#allWorkflows(form).length > 0;
  }

  #isWorkflowSelected(workflowId: string) {
    return this._selectedWorkflows.includes(workflowId);
  }

  #onWorkflowSelectedChanged(workflowId: string) {
    const pos = this._selectedWorkflows.indexOf(workflowId);
    if (pos >= 0) {
      this._selectedWorkflows.splice(pos, 1);
    } else {
      this._selectedWorkflows.push(workflowId);
    }
    this.requestUpdate();
  }

  async #onTreeSelectionChange(event: CustomEvent) {
    const target = event.target as UmbTreeElement;
    const selection = target.getSelection();
    if (selection.length > 0 && selection[0] != this.#sourceForm!.id) {
      const destinationFormId = selection[0];
      const { data } = await this.#formDetailRepository.requestByUnique(
        destinationFormId
      );
      if (data) {
        this._destinationForm = data;
      } else {
        this._destinationForm = null;
      }
    } else {
      this._destinationForm = null;
    }

    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  #onSelectAnotherFormClick()  {
    this._destinationForm = null;
  }

  async #copyWorkflows() {

    if (!this.#formDetailRepository)
      throw new Error("Repository is not available");
    if (!this.#sourceForm)
      throw new Error("Source form is not available");
    if (!this._destinationForm)
      throw new Error("Destination form is not available");

    const { error } = await this.#formDetailRepository.copyFormWorkflows(
      this.#sourceForm.unique,
      this._destinationForm.unique,
      this._selectedWorkflows,
    );

    if (!error) {
      this.#notificationContext?.peek("positive", {
        data: { message: this.localize.term("formCopyWorkflows_copiedWorkflowsSuccess") },
      });
      this._submitModal();
    } else {
      this.#notificationContext?.peek("danger", {
        data: { message: this.localize.term("formCopyWorkflows_copiedWorkflowsError") },
      });
      this._rejectModal();
    }
  }

  #renderWorkflowForStage(workflows: FormWorkflowWithTypeSettings[], stage: string) {
    return html`
      ${workflows.map(
        (workflow) =>
          html`<uui-table-row>
            <uui-table-cell>${this.localize.term("formWorkflows_" + stage)}</uui-table-cell>
            <uui-table-cell>${workflow.name}</uui-table-cell>
            <uui-table-cell>${workflow.workflowTypeName}</uui-table-cell>
            <uui-table-cell>
              <uui-toggle
                ?checked=${this.#isWorkflowSelected(workflow.id)}
                @change=${() => this.#onWorkflowSelectedChanged(workflow.id)}
              ></uui-toggle>
            </uui-table-cell>
          </uui-table-row>`)}`
  }

  render() {
    return html`
      ${when(this.#sourceForm,
        () => html`
          <umb-body-layout headline=${this.localize.term("formCopyWorkflows_title")}>
            <uui-box>
              <p><b>${this.localize.term("formCopyWorkflows_subtitle", this.#sourceForm!.name )}</b></p>
              ${when(!this.#formHasWorkflows(this.#sourceForm!),
                () => html`<p>${this.localize.term("formCopyWorkflows_noWorkflows")}</p>`)}

              ${when(this.#formHasWorkflows(this.#sourceForm!),
                () => html`
                  <p>${this.localize.term("formCopyWorkflows_selectedWorkflows")}</p>

                  <uui-table>
                    <uui-table-head>
                      <uui-table-head-cell>${this.localize.term("formCopyWorkflows_stage")}</uui-table-head-cell>
                      <uui-table-head-cell>${this.localize.term("formEntries_workflowAuditName")}</uui-table-head-cell>
                      <uui-table-head-cell>${this.localize.term("formEntries_workflowAuditType")}</uui-table-head-cell>
                      <uui-table-head-cell>${this.localize.term("formCopyWorkflows_selected")}?</uui-table-head-cell>
                    </uui-table-head>

                    ${this.#renderWorkflowForStage(this.#sourceForm!.formWorkflows.onSubmit, "onSubmit")}
                    ${this.#renderWorkflowForStage(this.#sourceForm!.formWorkflows.onApprove, "onApprove")}
                    ${this.#renderWorkflowForStage(this.#sourceForm!.formWorkflows.onReject, "onReject")}

                  </uui-table>

                  ${when(this._destinationForm,
                    () => html`
                      <p>
                        ${unsafeHTML(this.localize.term("formCopyWorkflows_selectedDestinationForm", this._destinationForm!.name))}
                        <small>(<a @click=${this.#onSelectAnotherFormClick}>${this.localize.term("formCopyWorkflows_selectAnotherForm")}</a>)</small>
                      </p>`)}
                  ${when(!this._destinationForm,
                    () => html`
                      <p>${this.localize.term("formCopyWorkflows_destinationForm")}</p>
                      <umb-tree
                        id="CopyToFolder"
                        alias="${FORMS_FORM_TREE_ALIAS}"
                        .props=${{
                          hideTreeRoot: true,
                          selectionConfiguration: {
                            multiple: false,
                          },
                          selectableFilter: (item: UmbTreeItemModelBase) =>
                            !item.isFolder && item.unique !== this.#sourceForm!.unique
                        }}
                        @selection-change=${this.#onTreeSelectionChange}
                      ></umb-tree>`)}
                `)}
            </uui-box>
            <uui-button
              slot="actions"
              id="cancel"
              label=${this.localize.term("general_cancel")}
              @click=${this._rejectModal}
              >${this.localize.term("general_cancel")}</uui-button
            >
            <uui-button
              form="CopyForm"
              slot="actions"
              type="submit"
              label=${this.localize.term("general_copy")}
              look="primary"
              color="positive"
              @click=${this.#copyWorkflows}
              ?disabled=${!this.#sourceForm || !this._destinationForm || this._selectedWorkflows.length === 0}
            ></uui-button>
          </umb-body-layout>
      `)}`;
  }

  static styles = [
    css`
      small a {
        text-decoration: underline;
        cursor: pointer;
      }
    `,
  ];
}

export default FormsFormCopyWorkflowsOptionsModalElement;

declare global {
  interface HTMLElementTagNameMap {
    "forms-form-copy-workflows-options-modal": FormsFormCopyWorkflowsOptionsModalElement;
  }
}

